  onEditMatchVotes: (match: MatchHistoryItem) => void;
  onLogout: () => void;
  onAddSquadPlayer: (player: Omit<SquadPlayer, 'id' | 'createdAt'>) => void;
  onRemoveSquadPlayer: (id: string) => void;
  onUpdateSquadPlayer: (id: string, updates: Partial<SquadPlayer>) => void;
