               </button>
            </div>
          </div>
        )}

        {currentTab === 'squad' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <SquadStatsView squad={squad} history={history} onAddPlayer={onAddSquadPlayer} onRemovePlayer={onRemoveSquadPlayer} onUpdatePlayer={onUpdateSquadPlayer} />
          </div>
        )}

        {currentTab === 'training' && (
          <TrainingView squad={activeSquad} history={trainingHistory} onSaveSession={onSaveTrainingSession} onUpdateSession={onUpdateTrainingSession} onDeleteSession={onDeleteTrainingSession} onAddSquadPlayer={onAddSquadPlayer} />
        )}

        {currentTab === 'planner' && (
           <MatchPlanner squad={activeSquad} />
        )}

        {currentTab === 'hub' && (
           <LeagueHubView playbook={playbook} onAddPlaybookItem={onAddPlaybookItem} onDeletePlaybookItem={onDeletePlaybookItem} />
        )}

      </main>

      <ConfirmationModal isOpen={isDeleteModalOpen} title="Delete Match Record?" message="Permanently remove match and stats? This cannot be undone." onConfirm={confirmDelete} onCancel={() => { setDeleteMatchId(null); setIsDeleteModalOpen(false); }} />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Button } from './Button';
import { SquadPlayer } from '../types';
import { TEAM_SIZE } from '../constants';

interface TeamSelectionModalProps {
  isOpen: boolean;
  squad: SquadPlayer[];
  onConfirm: (selections: { jersey: string; squadId: string; name: string }[]) => void;
  onCancel: () => void;
}

export const TeamSelectionModal: React.FC<TeamSelectionModalProps> = ({
  isOpen,
  squad,
  onConfirm,
  onCancel
}) => {
  // Map of Jersey Number (string) -> SquadPlayerId
  const [selections, setSelections] = useState<Record<string, string>>({});

  // Initialize
  useEffect(() => {
    if (isOpen) {
      setSelections({});
    }
  }, [isOpen]);

  const handleSelect = (jersey: string, squadId: string) => {
    setSelections(prev => ({
      ...prev,
      [jersey]: squadId
    }));
  };

  const handleImportLocked = () => {
    try {
      const saved = localStorage.getItem('LOCKED_MATCH_TEAM');
      if (saved) {
        const assignments = JSON.parse(saved); // Array of {jersey, squadId}
        const newSelections: Record<string, string> = {};

        let importedCount = 0;
        if (Array.isArray(assignments)) {
            assignments.forEach((a: any) => {
                if (a.squadId) {
                // Verify the squad player still exists
                if (squad.some(p => p.id === a.squadId)) {
                    newSelections[a.jersey] = a.squadId;
                    importedCount++;
                }
                }
            });
        }

        if (importedCount > 0) {
            setSelections(newSelections);
        } else {
            alert("No valid locked team found. Please lock a team in the Planner first.");
        }
      } else {
        alert("No locked team found. Go to the Planner and click 'Lock In Squad'.");
      }
    } catch (e) {
      console.error("Failed to load locked team", e);
    }
  };

  const handleSubmit = () => {
    const result = [];
    for (let i = 1; i <= TEAM_SIZE; i++) {
       const jersey = i.toString();
       const squadId = selections[jersey];
       if (squadId) {
         const player = squad.find(p => p.id === squadId);
         if (player) {
           result.push({ jersey, squadId, name: player.name });
         }
       }
    }
    onConfirm(result);
  };

  // Helper to get all IDs currently assigned to ANY jersey
  const getAllSelectedIds = () => Object.values(selections).filter(Boolean);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div 
        className="absolute inset-0 bg-black/60 backdrop-blur-sm" 
        onClick={onCancel}
      />

      <div className="relative bg-white dark:bg-[#1A1A1C] rounded-xl shadow-2xl max-w-4xl w-full max-h-[90vh] flex flex-col overflow-hidden animate-in fade-in zoom-in duration-200">
