               >
                 <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                 </svg>
                 <span>App Settings & User Guide</span>
               </button>
            </div>
          </div>
        )}

        {currentTab === 'squad' && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <SquadStatsView squad={squad} history={history} onAddPlayer={onAddSquadPlayer} onRemovePlayer={onRemoveSquadPlayer} onUpdatePlayer={onUpdateSquadPlayer} />
          </div>
        )}

        {currentTab === 'training' && (
          <TrainingView squad={activeSquad} history={trainingHistory} onSaveSession={onSaveTrainingSession} onUpdateSession={onUpdateTrainingSession} onDeleteSession={onDeleteTrainingSession} onAddSquadPlayer={onAddSquadPlayer} />
        )}

        {currentTab === 'planner' && (
           <MatchPlanner squad={activeSquad} />
        )}

        {currentTab === 'hub' && (
           <LeagueHubView 
             playbook={playbook} 
             onAddPlaybookItem={onAddPlaybookItem} 
             onDeletePlaybookItem={onDeletePlaybookItem} 
             controlledActiveTab={hubSection}
             onTabChange={onSetHubSection}
           />
        )}

      </main>

      <ConfirmationModal isOpen={isDeleteModalOpen} title="Delete Match Record?" message="Permanently remove match and stats? This cannot be undone." onConfirm={confirmDelete} onCancel={() => { setDeleteMatchId(null); setIsDeleteModalOpen(false); }} />
    </div>
  );
};

