                                      <p className="text-sm text-slate-700 dark:text-gray-300 font-medium leading-relaxed">{step}</p>
                                   </div>
                                ))}
                             </div>
                          </div>
                       </div>
                  </div>
               </div>
            </div>
         </div>
      )}
    </div>
  );
};

