              <input 
                 type="text" 
                 className="block w-full pl-12 pr-4 py-5 border-none rounded-3xl bg-white dark:bg-[#1A1A1C] text-slate-900 dark:text-white placeholder-gray-400 focus:ring-0 shadow-apple dark:shadow-none transition-all" 
