                 {playbook.length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-32 space-y-6 bg-white dark:bg-[#1A1A1C] rounded-[3rem] border-2 border-dashed border-gray-100 dark:border-white/5 text-gray-400">
