                                <div className="absolute inset-0 bg-gradient-to-t from-slate-900 to-transparent"></div>
                             </div>
                             <div className="p-6">
                                <h4 className="font-heading font-bold text-lg text-slate-900 dark:text-white mb-1">{play.title}</h4>
