                 <div className="flex items-center justify-between">
                    <h3 className="text-3xl font-heading font-black text-slate-900 dark:text-white">Create New Play</h3>
                    <button onClick={() => setIsCreating(false)} className="text-gray-400 hover:text-red-500 font-bold text-xs uppercase tracking-widest">Cancel</button>
