                 <div className="flex justify-end">
                    <Button onClick={handleSavePlay} className="px-10 py-4 bg-slate-900 dark:bg-white dark:text-slate-900 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl">Save Play</Button>
                 </div>
              </div>
