const MatchDayManagerView = () => {
  const [checkedItems, setCheckedItems] = useState<Set<string>>(new Set());

  const toggleCheck = (id: string) => {
    const next = new Set(checkedItems);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setCheckedItems(next);
  };

  const progress = Math.round((checkedItems.size / SAFETY_CHECKLIST.length) * 100);

  return (
    <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
      <div className="xl:col-span-2 space-y-6">
        <div className="bg-slate-900 dark:bg-white rounded-3xl p-6 text-white dark:text-slate-900 shadow-xl relative overflow-hidden">
           <div className="flex items-center justify-between relative z-10">
              <div>
                 <h2 className="text-2xl font-heading font-black tracking-tight mb-1">Pre-Game Command</h2>
                 <p className="text-sm opacity-70 font-medium">Logistics & Safety Checks</p>
              </div>
              <div className="text-xl font-bold">{progress}%</div>
           </div>
        </div>
        <div className="bg-white dark:bg-[#1A1A1C] rounded-3xl border border-gray-100 dark:border-white/5 overflow-hidden shadow-sm">
           <div className="divide-y divide-gray-100 dark:divide-white/5">
              {SAFETY_CHECKLIST.map(item => {
                 const isChecked = checkedItems.has(item.id);
                 return (
                    <div 
                      key={item.id}
                      onClick={() => toggleCheck(item.id)}
                      className={`flex items-center p-5 cursor-pointer transition-all duration-200 group ${isChecked ? 'bg-gray-50/50 dark:bg-white/5' : 'hover:bg-gray-50 dark:hover:bg-white/5'}`}
                    >
                       <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-xl mr-5 shadow-sm ${isChecked ? 'bg-green-100 dark:bg-green-900/20' : 'bg-white dark:bg-white/10 border border-gray-100 dark:border-white/5'}`}>
                          {item.icon}
                       </div>
                       <div className="flex-1">
                          <h4 className={`font-bold text-base transition-colors ${isChecked ? 'text-gray-500 line-through' : 'text-slate-900 dark:text-white'}`}>{item.label}</h4>
                          <p className="text-xs text-gray-400 dark:text-gray-500 font-medium mt-0.5">{item.sub}</p>
                       </div>
                       <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${isChecked ? 'bg-green-50 border-green-500' : 'border-gray-200 dark:border-white/20'}`}>
                          {isChecked && <svg className="w-3.5 h-3.5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
                       </div>
                    </div>
                 );
              })}
           </div>
        </div>
      </div>
      <div className="xl:col-span-1 space-y-6">
         <div className="bg-[#E02020] rounded-3xl p-6 text-white shadow-lg relative overflow-hidden group">
            <h3 className="font-heading font-black text-xl mb-1 text-white">CRT 6</h3>
            <p className="text-[10px] font-bold uppercase tracking-[0.2em] mb-4 opacity-80 text-white">Concussion Protocol</p>
            <div className="space-y-4">
               <div className="bg-black/20 rounded-xl p-3">
                  <p className="text-xs font-bold text-white">If in doubt, sit them out. No return to play today.</p>
               </div>
            </div>
         </div>
      </div>
    </div>
  );
};

interface LeagueHubViewProps {
  playbook: PlaybookItem[];
  onAddPlaybookItem: (item: Omit<PlaybookItem, 'id'>) => void;
  onDeletePlaybookItem: (id: string) => void;
  controlledActiveTab?: 'library' | 'planner' | 'playbook' | 'manual' | 'rules' | 'matchday';
  onTabChange?: (tab: any) => void;
}

export const LeagueHubView: React.FC<LeagueHubViewProps> = ({ 
  playbook, 
  onAddPlaybookItem, 
  onDeletePlaybookItem,
  controlledActiveTab,
  onTabChange
}) => {
  const [internalTab, setInternalTab] = useState<'library' | 'planner' | 'playbook' | 'manual' | 'rules' | 'matchday'>('library');
  const [selectedDrill, setSelectedDrill] = useState<Drill | null>(null);
  const [filterCategory, setFilterCategory] = useState<string>('All');
  const [searchQuery, setSearchQuery] = useState('');

  const [sessionBlocks, setSessionBlocks] = useState<PlanBlock[]>([]);
  const [sessionTitle, setSessionTitle] = useState('New Training Session');

  const [isCreating, setIsCreating] = useState(false);
  const [newPlayTitle, setNewPlayTitle] = useState('');
  const [newPlayData, setNewPlayData] = useState('');

  const activeTab = controlledActiveTab || internalTab;
  const setActiveTab = onTabChange || setInternalTab;

  const filteredDrills = useMemo(() => {
    return DRILL_LIBRARY.filter(d => {
      const matchesCategory = filterCategory === 'All' || d.category === filterCategory;
      const matchesSearch = d.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                            d.description.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [filterCategory, searchQuery]);

  const categories = ['All', 'Attack', 'Defense', 'Fitness', 'Core Skills', 'Kicking'];

  const getCategoryColor = (category: string) => {
    switch (category) {
      case 'Attack': return 'bg-blue-500';
      case 'Defense': return 'bg-red-500';
      case 'Fitness': return 'bg-purple-500';
      case 'Core Skills': return 'bg-emerald-500';
      case 'Kicking': return 'bg-amber-500';
      default: return 'bg-slate-500';
    }
  };

  const handleSavePlay = () => {
    if (!newPlayTitle.trim()) return;
    onAddPlaybookItem({
      title: newPlayTitle,
      type: 'Move',
      content: newPlayData || JSON.stringify({ pitchType: 'half', frames: [{ id: '1', tokens: [] }] }),
      createdAt: Date.now()
    });
    setIsCreating(false);
    setNewPlayTitle('');
    setNewPlayData('');
  };

  const addToPlan = (drill: Drill) => {
    const newBlock: PlanBlock = {
      id: Date.now().toString(),
      type: 'drill',
      title: drill.title,
      durationMin: drill.durationMin,
      drillId: drill.id
    };
    setSessionBlocks([...sessionBlocks, newBlock]);
  };

  const totalDuration = sessionBlocks.reduce((acc, b) => acc + b.durationMin, 0);

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500 relative min-h-[600px]">
      <div className="relative">
        <div className="flex border-b border-gray-200 dark:border-white/10 overflow-x-auto no-scrollbar pb-px">
          {[
            { id: 'library', label: 'Drill Library' },
            { id: 'planner', label: 'Session Planner' },
            { id: 'playbook', label: 'My Playbook' },
            { id: 'rules', label: "Ref's Corner" },
            { id: 'matchday', label: 'Match Day Manager' },
            { id: 'manual', label: 'Coach Manual' }
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => { setActiveTab(tab.id as any); setIsCreating(false); }}
              className={`py-4 px-6 text-sm font-bold border-b-[3px] transition-all whitespace-nowrap ${activeTab === tab.id ? 'border-brand text-brand' : 'border-transparent text-gray-500 hover:text-gray-700 dark:text-gray-400'}`}
            >
              {tab.label}
            </button>
          ))}
        </div>
        <div className="absolute right-0 top-0 bottom-0 w-8 bg-gradient-to-l from-[#F5F5F7] dark:from-[#0F0F10] to-transparent pointer-events-none md:hidden"></div>
      </div>

      {activeTab === 'manual' && <CoachManualView />}
      {activeTab === 'rules' && <RefCornerView />}
      {activeTab === 'matchday' && <MatchDayManagerView />}

      {activeTab === 'planner' && (
